using Microsoft.EntityFrameworkCore;
class BlogContext : DbContext
{
    public DbSet<Blog> Blogs => Set<Blog>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Blog>(entity =>
        {
            // Breaking change #1: EF 9 removed HasIndex for Cosmos (indexes are
            // managed server-side via indexing policies, not EF).
            // modelBuilder.Entity<Blog>().HasIndex(b => b.Name);  <-- REMOVED

            // Breaking change #2: EF 9 renamed the discriminator property from
            // "Discriminator" to "$type". Preserve the old name so existing
            // documents remain readable.
            entity.HasDiscriminator<string>("Discriminator");

            // Breaking change #3: EF 9 changed the default id format from
            // "EntityType|KeyValue" to just "KeyValue". Preserve the old format
            // so existing documents are still found.
            entity.HasPartitionKey(b => b.Id);
            entity.Property(b => b.Id)
                  .ToJsonProperty("id")
                  .HasValueGenerator<LegacyCosmosIdGenerator>();
        });
    }
}

// Value generator that reproduces the EF 8 "Discriminator|Key" id format.
using Microsoft.EntityFrameworkCore.ChangeTracking;
using Microsoft.EntityFrameworkCore.ValueGeneration;
class LegacyCosmosIdGenerator : ValueGenerator<string>
{
    public override bool GeneratesTemporaryValues => false;
    public override string Next(EntityEntry entry)
    {
        var discriminator = entry.Metadata.GetDiscriminatorValue()?.ToString()
            ?? entry.Metadata.ShortName();
        var key = entry.Property("Id").CurrentValue?.ToString();
        return $"{discriminator}|{key}";
    }
}

class Blog { public string Id { get; set; } public string Name { get; set; } }

